10030c44c4a7bca122f5675141e0bc4b.sql:
SELECT "family.hostName" AS "Tên chủ hộ", "family.ethnicity" AS "Dân tộc", "b1Point" AS "Điểm đánh giá B1", "family.isDTTS" AS "Dân tộc thiểu số" 
FROM households 
WHERE "family.hostName" ILIKE '%Trần Thị Liên%' AND "administrative.district" ILIKE '%Đắk Song%';

41dfe5908bd357642b770df8a3c766c2.sql:
SELECT "family.code" AS "Mã hộ gia đình", "family.hostName" AS "Tên chủ hộ", "family.hostGender" AS "Giới tính chủ hộ", "family.numberOfMembers" AS "Số thành viên hộ", "administrative.year" AS "Năm"
FROM households
WHERE classify = 'Hộ nghèo' AND "administrative.commune" ILIKE '%Đắk Lao%' AND "administrative.year" IN (2023, 2024);
